export interface OmopDbPerson {
    'provenance_id'?: string | null;
    'source_traceback'?: string | null;
    'created_at'?: string | null;
    'modified_at'?: string | null;
    'modified_by'?: string | null;
    'person_id'?: string | null;
    /**
     * OmopDbUser guidance: This field is meant to capture the biological sex at birth of the OmopDbPerson. This field should not be used to study gender identity issues. ETL conventions: Use the gender or sex value present in the data under the assumption that it is the biological sex at birth. If the source data captures gender identity it should be stored in the [OBSERVATION](https://ohdsi.github.io/CommonDataModel/cdm54.html#observation) table. [Accepted gender concepts](http://athena.ohdsi.org/search-terms/terms?domain=Gender&standardConcept=Standard&page=1&pageSize=15&query=). Please refer to the [THEMIS repository](https://ohdsi.github.io/Themis/tag_gender_concept_id.html) for detailed conventions on how to populate this field.
     */
    'gender_concept_id': string;
    /**
     * OmopDbUser guidance: Compute age using year_of_birth. ETL conventions: For data sources with date of birth, the year should be extracted. If no year of birth is available all the person\'s data should be dropped from the CDM instance. For additional information on how to populate this field, please refer to the [THEMIS repository](https://ohdsi.github.io/Themis/tag_year_of_birth.html).
     */
    'year_of_birth': number;
    'month_of_birth'?: number | null;
    'day_of_birth'?: number | null;
    'birth_datetime'?: string | null;
    /**
     * OmopDbUser guidance: This field captures race or ethnic background of the person. ETL conventions: Only use this field if you have information about race or ethnic background. The OmopDbVocabulary contains Concepts about the main races and ethnic backgrounds in a hierarchical system. Due to the imprecise nature of human races and ethnic backgrounds, this is not a perfect system. Mixed races are not supported. If a clear race or ethnic background cannot be established, use Concept_Id 0. [Accepted Race Concepts](http://athena.ohdsi.org/search-terms/terms?domain=Race&standardConcept=Standard&page=1&pageSize=15&query=).
     */
    'race_concept_id': string;
    /**
     * OmopDbUser guidance: This field captures Ethnicity as defined by the Office of Management and Budget (OMB) of the US Government: it distinguishes only between \"Hispanic\" and \"Not Hispanic\". Races and ethnic backgrounds are not stored here. ETL conventions: Only use this field if you have US-based data and a source of this information. Do not attempt to infer Ethnicity from the race or ethnic background of the OmopDbPerson. [Accepted ethnicity concepts](http://athena.ohdsi.org/search-terms/terms?domain=Ethnicity&standardConcept=Standard&page=1&pageSize=15&query=)
     */
    'ethnicity_concept_id': string;
    'location_id'?: string | null;
    'provider_id'?: string | null;
    'care_site_id'?: string | null;
    'person_source_value'?: string | null;
    'gender_source_value'?: string | null;
    'gender_source_concept_id'?: string | null;
    'race_source_value'?: string | null;
    'race_source_concept_id'?: string | null;
    'ethnicity_source_value'?: string | null;
    'ethnicity_source_concept_id'?: string | null;
    /**
     * OmopDbUser guidance: Not part of OMOP CDM. The conceptual type of OmopDbPerson under study, e.g. human, animal or environment, since data from non-human origin are also in scope. ETL conventions: None
     */
    'person_type_concept_id': string;
    'provided_by_organization_id'?: string | null;
}
