/**
 * The VISIT_DETAIL table is an optional table used to represents details of each record in the parent VISIT_OCCURRENCE table. A good example of this would be the movement between units in a hospital during an inpatient stay or claim lines associated with a one insurance claim. For every record in the VISIT_OCCURRENCE table there may be 0 or more records in the VISIT_DETAIL table with a 1:n relationship where n may be 0. The VISIT_DETAIL table is structurally very similar to VISIT_OCCURRENCE table and belongs to the visit domain.    PARENT CLASS DOCUMENTATION   DataLineageMixin:  Mixin class to add fields to a model for data lineage tracking.
 */
export interface OmopDbVisitDetail {
    'provenance_id'?: string | null;
    'source_traceback'?: string | null;
    'created_at'?: string | null;
    'modified_at'?: string | null;
    'modified_by'?: string | null;
    'visit_detail_id'?: string | null;
    /**
     * OmopDbUser guidance: None ETL conventions: None
     */
    'person_id': string;
    /**
     * OmopDbUser guidance: This field contains a concept id representing the kind of visit detail, like inpatient or outpatient. All concepts in this field should be standard and belong to the Visit domain. ETL conventions: Populate this field based on the kind of visit that took place for the person. For example this could be \"Inpatient Visit\", \"Outpatient Visit\", \"Ambulatory Visit\", etc. This table will contain standard concepts in the Visit domain. These concepts are arranged in a hierarchical structure to facilitate cohort definitions by rolling up to generally familiar Visits adopted in most healthcare systems worldwide. [Accepted Concepts](https://athena.ohdsi.org/search-terms/terms?domain=Visit&standardConcept=Standard&page=1&pageSize=15&query=).
     */
    'visit_detail_concept_id': string;
    /**
     * OmopDbUser guidance: This is the date of the start of the encounter. This may or may not be equal to the date of the Visit the Visit Detail is associated with. ETL conventions: When populating VISIT_DETAIL_START_DATE, you should think about the patient experience to make decisions on how to define visits. Most likely this should be the date of the patient-provider interaction.
     */
    'visit_detail_start_date': string;
    'visit_detail_start_datetime'?: string | null;
    /**
     * OmopDbUser guidance: This the end date of the patient-provider interaction.  If a OmopDbPerson is still an inpatient in the hospital at the time of the data extract and does not have a visit_end_date, then set the visit_end_date to the date of the data pull. ETL conventions: Visit Detail end dates are mandatory. If end dates are not provided in the source there are three ways in which to derive them:<br>  - Outpatient Visit Detail: visit_detail_end_datetime = visit_detail_start_datetime  - Emergency Room Visit Detail: visit_detail_end_datetime = visit_detail_start_datetime  - Inpatient Visit Detail: Usually there is information about discharge. If not, you should be able to derive the end date from the sudden decline of activity or from the absence of inpatient procedures/drugs.  - Non-hospital institution Visit Details: Particularly for claims data, if end dates are not provided assume the visit is for the duration of month that it occurs.<br>  For Inpatient Visit Details ongoing at the date of ETL, put date of processing the data into visit_detai_end_datetime and visit_detail_type_concept_id with 32220 \"Still patient\" to identify the visit as incomplete.  All other Visits Details: visit_detail_end_datetime = visit_detail_start_datetime.
     */
    'visit_detail_end_date': string;
    'visit_detail_end_datetime'?: string | null;
    /**
     * OmopDbUser guidance: Use this field to understand the provenance of the visit detail record, or where the record comes from. ETL conventions: Populate this field based on the provenance of the visit detail record, as in whether it came from an EHR record or billing claim. [Accepted Concepts](https://athena.ohdsi.org/search-terms/terms?domain=Type+OmopDbConcept&standardConcept=Standard&page=1&pageSize=15&query=). A more detailed explanation of each Type OmopDbConcept can be found on the [vocabulary wiki](https://github.com/OHDSI/OmopDbVocabulary-v5.0/wiki/Vocab.-TYPE_CONCEPT).
     */
    'visit_detail_type_concept_id': string;
    'provider_id'?: string | null;
    'care_site_id'?: string | null;
    'visit_detail_source_value'?: string | null;
    'visit_detail_source_concept_id'?: string | null;
    'admitted_from_concept_id'?: string | null;
    'admitted_from_source_value'?: string | null;
    'discharged_to_source_value'?: string | null;
    'discharged_to_concept_id'?: string | null;
    'preceding_visit_detail_id'?: string | null;
    'parent_visit_detail_id'?: string | null;
    /**
     * OmopDbUser guidance: Use this field to link the VISIT_DETAIL record to its VISIT_OCCURRENCE. ETL conventions: Put the VISIT_OCCURRENCE_ID that subsumes the VISIT_DETAIL record here.
     */
    'visit_occurrence_id': string;
    'provided_by_organization_id'?: string | null;
}
